/**
 * Seeded, bounded random generator over the checker's SUPPORTED node grammar. Never emits volatile functions, bnode
 * generators, SERVICE, aggregates or anything else the counterexample oracle refuses, so every generated tree is
 * differentially testable. Determinism contract: the same seed always produces an ExactTreeEquality-equal tree.
 */
final class RandomTreeGenerator {
	private static final int MAX_DEPTH = 5;
	private static final int NODE_BUDGET = 25;

	TupleExpr generate(long seed) {
		Random rnd = new Random(seed);
		TupleExpr tree = tuple(rnd, new int[] { NODE_BUDGET }, 0);
		if (rnd.nextInt(10) == 0) {
			return new QueryRoot(tree);
		}
		return tree;
	}

	private TupleExpr tuple(Random rnd, int[] budget, int depth) {
		budget[0]--;
		if (depth >= MAX_DEPTH || budget[0] <= 0) {
			return leaf(rnd);
		}
		int pick = rnd.nextInt(52);
		if (pick < 10) {
			return new Join(tuple(rnd, budget, depth + 1), tuple(rnd, budget, depth + 1));
		}
		if (pick < 18) {
			return new Union(tuple(rnd, budget, depth + 1), tuple(rnd, budget, depth + 1));
		}
		if (pick < 24) {
			LeftJoin leftJoin = new LeftJoin(tuple(rnd, budget, depth + 1), tuple(rnd, budget, depth + 1));
			if (rnd.nextBoolean()) {
				leftJoin.setCondition(condition(rnd));
			}
			return leftJoin;
		}
		if (pick < 30) {
			return new Filter(tuple(rnd, budget, depth + 1), condition(rnd));
		}
		if (pick < 34) {
			return new Difference(tuple(rnd, budget, depth + 1), tuple(rnd, budget, depth + 1));
		}
		if (pick < 38) {
			return projection(rnd, tuple(rnd, budget, depth + 1));
		}
		if (pick < 42) {
			return extension(rnd, tuple(rnd, budget, depth + 1));
		}
		if (pick < 44) {
			return new Distinct(tuple(rnd, budget, depth + 1));
		}
		if (pick < 46) {
			Order order = new Order(tuple(rnd, budget, depth + 1));
			order.addElement(new OrderElem(FuzzVocabulary.variable(rnd), true));
			return order;
		}
		if (pick < 48) {
			return new Slice(tuple(rnd, budget, depth + 1), rnd.nextInt(3), 1 + rnd.nextInt(4));
		}
		if (pick < 49) {
			return new Reduced(tuple(rnd, budget, depth + 1));
		}
		return leaf(rnd);
	}

	private TupleExpr leaf(Random rnd) {
		int pick = rnd.nextInt(10);
		if (pick < 6) {
			return statementPattern(rnd);
		}
		if (pick < 8) {
			return values(rnd);
		}
		if (pick < 9) {
			return new SingletonSet();
		}
		return new EmptySet();
	}

	private StatementPattern statementPattern(Random rnd) {
		return new StatementPattern(
				FuzzVocabulary.variable(rnd),
				FuzzVocabulary.constant(FuzzVocabulary.predicate(rnd)),
				FuzzVocabulary.variable(rnd));
	}

	private BindingSetAssignment values(Random rnd) {
		List<String> names = new ArrayList<>();
		names.add(FuzzVocabulary.variableName(rnd));
		if (rnd.nextBoolean()) {
			String second = FuzzVocabulary.variableName(rnd);
			if (!names.contains(second)) {
				names.add(second);
			}
		}
		List<BindingSet> rows = new ArrayList<>();
		int rowCount = 1 + rnd.nextInt(3);
		for (int i = 0; i < rowCount; i++) {
			List<org.eclipse.rdf4j.model.Value> rowValues = new ArrayList<>();
			for (String ignored : names) {
				// Occasional null value models an UNDEF column.
				rowValues.add(rnd.nextInt(5) == 0 ? null : FuzzVocabulary.value(rnd));
			}
			rows.add(new ListBindingSet(names, rowValues));
		}
		BindingSetAssignment assignment = new BindingSetAssignment();
		assignment.setBindingNames(new LinkedHashSet<>(names));
		assignment.setBindingSets(rows);
		return assignment;
	}

	private Projection projection(Random rnd, TupleExpr arg) {
		ProjectionElemList elements = new ProjectionElemList();
		Set<String> chosen = new LinkedHashSet<>();
		int count = 1 + rnd.nextInt(3);
		for (int i = 0; i < count; i++) {
			chosen.add(FuzzVocabulary.variableName(rnd));
		}
		for (String name : chosen) {
			elements.addElement(new ProjectionElem(name));
		}
		return new Projection(arg, elements, rnd.nextInt(4) == 0);
	}

	private Extension extension(Random rnd, TupleExpr arg) {
		// A vocabulary variable name (not fresh) makes re-binding hazards reachable on purpose.
		String name = rnd.nextBoolean() ? FuzzVocabulary.variableName(rnd) : "fresh" + rnd.nextInt(2);
		ValueExpr expr = rnd.nextBoolean()
				? new ValueConstant(FuzzVocabulary.value(rnd))
				: FuzzVocabulary.variable(rnd);
		return new Extension(arg, new ExtensionElem(expr, name));
	}

	private ValueExpr condition(Random rnd) {
		if (rnd.nextBoolean()) {
			return new Compare(
					FuzzVocabulary.variable(rnd),
					new ValueConstant(FuzzVocabulary.value(rnd)),
					rnd.nextBoolean() ? Compare.CompareOp.EQ : Compare.CompareOp.GT);
		}
		return new SameTerm(FuzzVocabulary.variable(rnd), FuzzVocabulary.variable(rnd));
	}
}
